mapper.select:
SELECT A.ID, A.INSTCD, A.USERID, U.USERNM AS CURRENT_NAME, A.REVISIONMEMO AS SNAPSHOT_NAME, A.STATUS, TO_CHAR(A.SUBMIT_DT, 'YYYY-MM-DD') AS SUBMIT_DT, TO_CHAR(A.CHANGE_DT, 'YYYY-MM-DD') AS CHANGE_DT, A.BATCH_YN, A.SKIP_REASON, A.SOURCE_REVISION, A.SCREEN_ID, A.TRANSACTION_ID, A.UPDATED_BY, A.MEMO FROM TBREPOCHANGE A JOIN TBUSER U ON A.INSTCD = U.INSTCD LEFT JOIN TBAUDITHIST H ON A.ID = H.TARGET_ID WHERE 1 = 1
AND A.INSTCD = #{instCd}
AND A.STATUS = #{status}
AND NVL(U.USERNM, ' ') <> NVL(A.REVISIONMEMO, ' ')
ORDER BY A.INSTCD, A.CHANGE_DT DESC

